// Generate receipt image using @napi-rs/canvas
const { createCanvas, GlobalFonts } = require('@napi-rs/canvas');

const ordenPago = $input.first().json;
const orderItems = $input.all();

// Create canvas
const canvas = createCanvas(500, 600);
const ctx = canvas.getContext('2d');

// Background
ctx.fillStyle = '#ffffff';
ctx.fillRect(0, 0, 500, 600);

// Header
ctx.fillStyle = '#1e3c72';
ctx.fillRect(0, 0, 500, 80);
ctx.fillStyle = '#ffffff';
ctx.font = 'bold 24px Arial';
ctx.fillText('COMPROBANTE DE PAGO', 85, 50);

// Order info
ctx.fillStyle = '#333333';
ctx.font = '16px Arial';
ctx.fillText('Orden #: ' + ordenPago.order_id, 30, 120);
ctx.fillText('Cliente: ' + (ordenPago.customer_name || 'Cliente'), 30, 145);

// Line separator
ctx.strokeStyle = '#cccccc';
ctx.beginPath();
ctx.moveTo(30, 170);
ctx.lineTo(470, 170);
ctx.stroke();

// Products
let y = 200;
for (const item of orderItems) {
  const product = item.json;
  ctx.fillStyle = '#333333';
  ctx.font = 'bold 14px Arial';
  ctx.fillText(product.product_name, 30, y);

  y += 22;
  ctx.fillStyle = '#666666';
  ctx.font = '14px Arial';
  const lineTotal = parseFloat(product.total_bs).toFixed(2);
  ctx.fillText(product.quantity + ' x ' + lineTotal + ' BS = ' + lineTotal + ' BS', 30, y);

  y += 30;
}

// Total
ctx.strokeStyle = '#cccccc';
ctx.beginPath();
ctx.moveTo(30, y);
ctx.lineTo(470, y);
ctx.stroke();

y += 20;
ctx.fillStyle = '#1e3c72';
ctx.font = 'bold 20px Arial';
ctx.fillText('TOTAL: ' + parseFloat(ordenPago.monto_bs).toFixed(2) + ' BS', 30, y);

// Status
ctx.fillStyle = '#28a745';
ctx.font = 'bold 18px Arial';
ctx.fillText('PAGADO', 195, y + 40);

// Get base64 image
const imageBase64 = canvas.toDataURL('image/png').split(',')[1];

return [{
  json: {
    orden_pago_uuid: ordenPago.orden_pago_uuid,
    order_id: ordenPago.order_id,
    customer_phone: ordenPago.customer_phone,
    customer_name: ordenPago.customer_name,
    monto_bs: ordenPago.monto_bs,
    image_base64: imageBase64
  }
}];

// Check if BDV returned code 1000
const bdvResponse = $input.first().json;

if (bdvResponse.code !== 1000) {
  throw new Error('Payment validation failed: ' + (bdvResponse.message || 'Unknown error'));
}

return $input.all();
